  const raw = fs.readFileSync(f, 'utf8');
  for (const line of raw.split('\n')) {
    if (!line.trim()) continue;
    try {
      const o = JSON.parse(line);
      if (o.role !== 'user') continue;
      const c = o.message?.content;
      let text = '';
      if (Array.isArray(c)) {
        for (const part of c) {
          if (part.type === 'text' && part.text) text += part.text;
        }
      } else if (typeof c === 'string') text = c;
      text = text.replace(/<user_query>\\s*/g,'').replace(/<\\/user_query>/g,'').trim();
      if (text.length > 30 && text.length < 2000) userSnippets.push({ file: path.basename(path.dirname(f)), len: text.length, preview: text.slice(0, 500) });
    } catch {}
  }
}
